-- Generated candidate import. Review the CSV/report before running.
-- Existing rows are never updated or deleted. Duplicate priority: JAN, URL, maker+name.
begin;
create temporary table product_backfill_candidates (name text, maker text, work_title text, series_name text, character_name text, genre text, price integer, release_period text, jan_code text, official_url text, image_url text, source_checked_at date) on commit drop;
select name, maker, work_title, series_name, character_name, genre, price, release_period, jan_code, official_url, image_url, source_checked_at from product_backfill_candidates c
where not exists (select 1 from public.products p where
  (c.jan_code is not null and p.jan_code = c.jan_code) or
  (c.official_url is not null and p.official_url = c.official_url) or
  (lower(trim(p.maker)) = lower(trim(c.maker)) and lower(trim(p.name)) = lower(trim(c.name)))
)
on conflict do nothing;
commit;
